  });
  const [passwordMessage, setPasswordMessage] = useState("");

  // Fetch profile
  useEffect(() => {
    const fetchProfile = async () => {
      try {
        const res = await API.get("/users/profile");
        const u = res.data.user;
        setUser(u);
        setFormData({
          firstName: u.firstName || "",
          lastName: u.lastName || "",
          contactNumber: u.contactNumber || "",
          collegeName: u.collegeName || "",
          interests: u.interests || [],
          followedOrganisers: u.followedOrganisers || [],
        });
      } catch (err) {
        console.error(err);
        setError("Failed to load profile");
      }
    };

    fetchProfile();
  }, []);

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleUpdate = async (e) => {
    e.preventDefault();
    setMessage("");
    setError("");

    try {
      const updates = {
        firstName: formData.firstName,
        lastName: formData.lastName,
        contactNumber: formData.contactNumber,
        collegeName: formData.collegeName,
        interests: formData.interests,
        followedOrganisers: formData.followedOrganisers,
      };

      const res = await API.put("/users/profile", updates);
      setUser(res.data.user);
      setEditing(false);
      setMessage("Profile updated successfully!");
    } catch (err) {
      console.error(err);
      setError("Failed to update profile");
    }
  };

  const handlePasswordChange = async (e) => {
    e.preventDefault();
    setPasswordMessage("");

    if (passwordData.newPassword !== passwordData.confirmPassword) {
      setPasswordMessage("New passwords do not match");
      return;
    }

    try {
      await API.put("/users/change-password", passwordData); // make backend route
      setPasswordData({ currentPassword: "", newPassword: "", confirmPassword: "" });
      setPasswordMessage("Password updated successfully!");
    } catch (err) {
      console.error(err);
      setPasswordMessage(err.response?.data?.message || "Failed to change password");
    }
  };

  if (!user) return <p style={{ textAlign: "center" }}>Loading profile...</p>;

  return (
    <div style={styles.container}>
      <h2>My Profile</h2>

      {message && <p style={styles.success}>{message}</p>}
      {error && <p style={styles.error}>{error}</p>}

      {!editing ? (
        <div style={styles.profileBox}>
          <p><strong>First Name:</strong> {user.firstName}</p>
          <p><strong>Last Name:</strong> {user.lastName}</p>
          <p><strong>Email:</strong> {user.email}</p>
          <p><strong>Participant Type:</strong> {user.participantType}</p>
          <p><strong>Contact Number:</strong> {user.contactNumber || "N/A"}</p>
          <p><strong>College/Organization:</strong> {user.collegeName || "N/A"}</p>
          <p><strong>Interests:</strong> {(user.interests || []).join(", ")}</p>
          <p><strong>Followed Clubs:</strong> {(user.followedOrganisers || []).map(o => o.name).join(", ")}</p>

          <button style={styles.button} onClick={() => setEditing(true)}>
            Edit Profile
          </button>
        </div>
      ) : (
        <form onSubmit={handleUpdate} style={styles.form}>
          <input
            type="text"
            name="firstName"
            placeholder="First Name"
            value={formData.firstName}
            onChange={handleChange}
            required
            style={styles.input}
          />
          <input
            type="text"
            name="lastName"
            placeholder="Last Name"
            value={formData.lastName}
            onChange={handleChange}
            required
            style={styles.input}
          />
          <input
            type="text"
            name="contactNumber"
            placeholder="Contact Number"
            value={formData.contactNumber}
            onChange={handleChange}
            style={styles.input}
          />
          <input
            type="text"
            name="collegeName"
            placeholder="College / Organization Name"
            value={formData.collegeName}
            onChange={handleChange}
            style={styles.input}
          />

          {/* Interests */}
          <input
            type="text"
            name="interests"
            placeholder="Interests (comma separated)"
            value={formData.interests.join(", ")}
            onChange={(e) =>
              setFormData({ ...formData, interests: e.target.value.split(",").map(i => i.trim()) })
            }
            style={styles.input}
          />

          {/* Followed Organisers */}
          <input
            type="text"
            name="followedOrganisers"
            placeholder="Followed Clubs (comma separated)"
            value={(formData.followedOrganisers || []).map(o => o.name || o).join(", ")}
            onChange={(e) =>
              setFormData({ ...formData, followedOrganisers: e.target.value.split(",").map(i => ({ name: i.trim() })) })
            }
            style={styles.input}
          />

          <div style={{ display: "flex", gap: "10px" }}>
            <button type="submit" style={styles.button}>Save</button>
            <button type="button" style={styles.cancelBtn} onClick={() => setEditing(false)}>Cancel</button>
          </div>
        </form>
      )}

      {/* Password Reset */}
      <div style={{ marginTop: "30px" }}>
        <h3>Change Password</h3>
        {passwordMessage && <p style={passwordMessage.includes("success") ? styles.success : styles.error}>{passwordMessage}</p>}
        <form onSubmit={handlePasswordChange} style={styles.form}>
          <input
            type="password"
            name="currentPassword"
            placeholder="Current Password"
            value={passwordData.currentPassword}
            onChange={(e) => setPasswordData({ ...passwordData, currentPassword: e.target.value })}
            required
            style={styles.input}
          />
          <input
            type="password"
            name="newPassword"
            placeholder="New Password"
            value={passwordData.newPassword}
            onChange={(e) => setPasswordData({ ...passwordData, newPassword: e.target.value })}
            required
            style={styles.input}
          />
          <input
            type="password"
            name="confirmPassword"
            placeholder="Confirm New Password"
            value={passwordData.confirmPassword}
            onChange={(e) => setPasswordData({ ...passwordData, confirmPassword: e.target.value })}
            required
            style={styles.input}
          />
          <button type="submit" style={styles.button}>Change Password</button>
        </form>
      </div>
    </div>
  );
};

const styles = {
  container: {
    maxWidth: "600px",
    margin: "60px auto",
    padding: "30px",
    border: "1px solid #ddd",
    borderRadius: "8px",
    backgroundColor: "#fff",
  },
  profileBox: {
    marginTop: "20px",
  },
  form: {
    display: "flex",
    flexDirection: "column",
    gap: "15px",
    marginTop: "20px",
  },
  input: {
    padding: "10px",
    borderRadius: "5px",
    border: "1px solid #ccc",
  },
  button: {
    padding: "10px",
    borderRadius: "5px",
    border: "none",
    backgroundColor: "#007bff",
    color: "#fff",
    cursor: "pointer",
  },
  cancelBtn: {
    padding: "10px",
    borderRadius: "5px",
    border: "none",
    backgroundColor: "#6c757d",
    color: "#fff",
    cursor: "pointer",
  },
  success: { color: "green" },
  error: { color: "red" },
};

export default Profile;
